// ---------- Game constants ----------

const COLORS = [
  { id: 1, top: "#FF6B6B", bottom: "#CC2222", name: "red" },
  { id: 2, top: "#FFD93D", bottom: "#CC9900", name: "yellow" },
  { id: 3, top: "#6BCB77", bottom: "#228B22", name: "green" },
  { id: 4, top: "#4D96FF", bottom: "#1A5CC8", name: "blue" },
  { id: 5, top: "#FF922B", bottom: "#C85500", name: "orange" },
  { id: 6, top: "#CC77FF", bottom: "#8B22CC", name: "purple" },
  { id: 7, top: "#FF77B4", bottom: "#CC2288", name: "pink" },
  { id: 8, top: "#4ECDC4", bottom: "#1A9991", name: "teal" },
  { id: 9, top: "#B5803A", bottom: "#7A4E10", name: "brown" },
  { id: 10, top: "#E8E8E8", bottom: "#AAAAAA", name: "white" },
];

const TUBE_CAPACITY = 4;
const TUBE_W = 52;
const TUBE_H = 160;
const TUBE_GAP = 16;

const MAX_LEVEL = 5000;

const BG_GRADIENTS = [
  "linear-gradient(135deg, #0f2027, #203a43, #2c5364)",
  "linear-gradient(135deg, #42275a, #734b6d)",
  "linear-gradient(135deg, #134e5e, #71b280)",
  "linear-gradient(135deg, #1e3c72, #2a5298)",
  "linear-gradient(135deg, #3a1c71, #d76d77, #ffaf7b)",
  "linear-gradient(135deg, #16222a, #3a6073)",
];

// Procedural difficulty curve over 5000 levels:
//   1-5    : 2-3 colors, 2 empty
//   6-25   : 3-4 colors, 2 empty
//   26-40  : 3-5 colors, 2 empty
//   41-75  : 4-6 colors, 2 empty
//   76-160 : 5-7 colors, 2 empty
//   161-1500 : 6-8 colors, 2 empty
//   1501-3000: 7-9 colors, 2 empty
//   3001-5000: 8-10 colors, 2 empty
// ---------- Core game helpers ----------

function getLevelConfig(levelIdx) {
  return getLevelConfigFromConfig(levelIdx);
}

function getColorById(id) {
  return COLORS.find((c) => c.id === id);
}

// Seeded PRNG (mulberry32) so each level index always gives the same puzzle
function seededRng(seed) {
  let s = seed >>> 0;
  return () => {
    s += 0x6d2b79f5;
    let t = s;
    t = Math.imul(t ^ (t >>> 15), t | 1);
    t ^= t + Math.imul(t ^ (t >>> 7), t | 61);
    return ((t ^ (t >>> 14)) >>> 0) / 0xffffffff;
  };
}

function generateLevel(levelIdx) {
  const { colors: numColors, empty } = getLevelConfig(levelIdx);
  const rng = seededRng(levelIdx * 2654435761 + 1);
  const all = [];
  COLORS.slice(0, numColors).forEach((c) => {
    for (let i = 0; i < TUBE_CAPACITY; i++) all.push(c.id);
  });
  // Fisher-Yates with seeded rng
  for (let i = all.length - 1; i > 0; i--) {
    const j = Math.floor(rng() * (i + 1));
    [all[i], all[j]] = [all[j], all[i]];
  }
  const tubes = [];
  for (let i = 0; i < numColors; i++)
    tubes.push(all.slice(i * TUBE_CAPACITY, (i + 1) * TUBE_CAPACITY));
  for (let i = 0; i < empty; i++) tubes.push([]);
  return tubes;
}

function isSolved(tube) {
  if (!tube.length) return false;
  if (tube.length !== TUBE_CAPACITY) return false;
  return tube.every((c) => c === tube[0]);
}
function isGameWon(tubes) {
  return tubes.every((t) => !t.length || isSolved(t));
}

function canPour(from, to) {
  if (!from.length) return false;
  if (to.length >= TUBE_CAPACITY) return false;
  if (!to.length) return true;
  return from[from.length - 1] === to[to.length - 1];
}

function applyPour(tubes, fromIdx, toIdx) {
  const t = tubes.map((x) => [...x]);
  const from = t[fromIdx],
    to = t[toIdx];
  const col = from[from.length - 1];
  while (
    from.length &&
    from[from.length - 1] === col &&
    to.length < TUBE_CAPACITY
  )
    to.push(from.pop());
  return t;
}

function countPour(from, to) {
  if (!from.length) return 0;
  const col = from[from.length - 1];
  let n = 0;
  for (let i = from.length - 1; i >= 0 && from[i] === col; i--) n++;
  return Math.min(n, TUBE_CAPACITY - to.length);
}

// ─── liquid blocks builder ────────────────────────────────────────────────────
function buildBlocks(tubeArray, fillCount) {
  const display = tubeArray.slice(0, fillCount);
  const filled = [...display].reverse();
  const blocks = [];
  filled.forEach((cid) => {
    if (blocks.length && blocks[blocks.length - 1].colorId === cid)
      blocks[blocks.length - 1].count++;
    else blocks.push({ colorId: cid, count: 1 });
  });
  return blocks;
}

// Flat solid color — no gradient
function blockBg(colorId) {
  const col = getColorById(colorId);
  return col ? col.top : "#888";
}

