// ─── TubeVisual ───────────────────────────────────────────────────────────────
function TubeVisual({
  tube,
  fillOverride,
  isSelected,
  isHint,
  solved,
  onClick,
  style,
}) {
  const fill = fillOverride !== undefined ? fillOverride : tube.length;
  const blocks = buildBlocks(tube, fill);
  const empty = TUBE_CAPACITY - fill;

  return (
    <div
      onClick={onClick}
      style={{
        cursor: onClick ? "pointer" : "default",
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        gap: 0,
        transition: "transform 0.2s ease, filter 0.2s",
        transform: isSelected ? "translateY(-18px) scale(1.05)" : "none",
        filter: isHint ? "drop-shadow(0 0 10px #FFD93D)" : "none",
        ...style,
      }}
    >
      {solved ? (
        <div
          style={{
            animation: "corkPop 0.35s cubic-bezier(0.34,1.56,0.64,1) both",
          }}
        >
          <Cork />
        </div>
      ) : (
        <div
          style={{
            width: TUBE_W,
            height: 8,
            borderRadius: "6px 6px 0 0",
            background: isSelected ? "rgba(255,255,255,0.25)" : "transparent",
            transition: "background 0.2s",
          }}
        />
      )}
      <div
        style={{
          width: TUBE_W,
          height: TUBE_H,
          borderRadius: "0 0 28px 28px",
          border: `2.5px solid ${isSelected ? "#FFD93D" : solved ? "#6BCB77" : "rgba(255,255,255,0.18)"}`,
          background: "rgba(255,255,255,0.06)",
          backdropFilter: "blur(4px)",
          overflow: "hidden",
          display: "flex",
          flexDirection: "column",
          boxShadow: isSelected
            ? "0 0 20px #FFD93D88, inset 0 0 10px rgba(255,255,255,0.08)"
            : solved
              ? "0 0 16px #6BCB7788"
              : "inset 0 0 10px rgba(0,0,0,0.2), 0 4px 15px rgba(0,0,0,0.3)",
          transition: "border 0.2s, box-shadow 0.2s",
          position: "relative",
        }}
      >
        <div
          style={{
            position: "absolute",
            top: 0,
            left: 8,
            width: 8,
            height: "70%",
            background: "rgba(255,255,255,0.12)",
            borderRadius: "0 0 4px 4px",
            pointerEvents: "none",
          }}
        />
        {empty > 0 && <div style={{ flex: empty }} />}
        {blocks.map((b, i) => {
          const col = getColorById(b.colorId);
          if (!col) return null;
          return (
            <div
              key={i}
              style={{
                width: "100%",
                flex: b.count,
                background: blockBg(b.colorId),
                borderRadius: i === blocks.length - 1 ? "0 0 26px 26px" : "0",
                transition: "flex 0.18s ease",
              }}
            />
          );
        })}
      </div>
    </div>
  );
}

// ─── AnimatedPour ─────────────────────────────────────────────────────────────
// Continuous rAF-driven animation with a visible liquid stream between tubes.
//
// Phase timeline (ms):
//   rise(120) → move(320) → tilt(240) → pour(800) → untilt(200) → return(320)
//
// During "pour":
//   • srcFillF  decreases 0→pourCount  (continuous float)
//   • destFillF increases 0→pourCount  (continuous float)
//   • A SVG stream is drawn between the two tube openings

const POUR_DUR = 800; // ms for the liquid transfer

// ---------- Pour animation ----------

function AnimatedPour({
  fromTube,
  fromPos,
  toPos,
  pourColor,
  pourCount,
  toFillBefore,
  toFillAfterTube,
  onDone,
}) {
  const [phase, setPhase] = useState("rise");
  // continuous fractional fills driven by rAF
  const [srcFillF, setSrcFillF] = useState(fromTube.length);
  const [destFillF, setDestFillF] = useState(toFillBefore);
  const rafRef = useRef(null);

  const dx = toPos.x - fromPos.x;
  const dy = toPos.y - fromPos.y;
  const tiltDir = dx < 0 ? -1 : 1;
  const tiltAngle = tiltDir * 108;
  const moveX = dx;
  const moveY = dy - 10;

  useEffect(() => {
    let cancelled = false;

    async function run() {
      // ── rise ──
      setPhase("rise");
      await sleep(120);
      if (cancelled) return;

      // ── move ──
      setPhase("move");
      await sleep(320);
      if (cancelled) return;

      // ── tilt ──
      setPhase("tilt");
      await sleep(240);
      if (cancelled) return;

      // ── pour  (rAF loop) ──
      setPhase("pour");
      await new Promise((resolve) => {
        const startTime = performance.now();
        function frame(now) {
          if (cancelled) {
            resolve();
            return;
          }
          const t = Math.min((now - startTime) / POUR_DUR, 1);
          // ease-in-out
          const eased = t < 0.5 ? 2 * t * t : -1 + (4 - 2 * t) * t;
          const transferred = eased * pourCount;
          setSrcFillF(fromTube.length - transferred);
          setDestFillF(toFillBefore + transferred);
          if (t < 1) {
            rafRef.current = requestAnimationFrame(frame);
          } else {
            setSrcFillF(fromTube.length - pourCount);
            setDestFillF(toFillBefore + pourCount);
            resolve();
          }
        }
        rafRef.current = requestAnimationFrame(frame);
      });
      if (cancelled) return;

      // ── untilt ──
      setPhase("untilt");
      await sleep(200);
      if (cancelled) return;

      // ── return ──
      setPhase("return");
      await sleep(300);
      // Fire onDone BEFORE the flying tube snaps to origin, so the static
      // tube already shows tubesAfter when the flyer disappears.
      if (!cancelled) onDone();
      await sleep(20);
      if (!cancelled) setPhase("done");
    }

    run();
    return () => {
      cancelled = true;
      if (rafRef.current) cancelAnimationFrame(rafRef.current);
    };
  }, []); // eslint-disable-line

  const transforms = {
    rise: "translate(0px, -50px) rotate(0deg)",
    move: `translate(${moveX}px, ${moveY - 50}px) rotate(0deg)`,
    tilt: `translate(${moveX}px, ${moveY - 50}px) rotate(${tiltAngle}deg)`,
    pour: `translate(${moveX}px, ${moveY - 50}px) rotate(${tiltAngle}deg)`,
    untilt: `translate(${moveX}px, ${moveY - 50}px) rotate(0deg)`,
    return: "translate(0px, 0px) rotate(0deg)",
    done: "translate(0px, 0px) rotate(0deg)",
  };
  const transitions = {
    rise: "transform 0.12s ease-out",
    move: "transform 0.32s cubic-bezier(0.4,0,0.2,1)",
    tilt: "transform 0.24s ease-in",
    pour: "transform 0s",
    untilt: "transform 0.20s ease-out",
    return: "transform 0.32s cubic-bezier(0.4,0,0.2,1)",
    done: "none",
  };

  // ── Pixel heights for liquid blocks in the flying tube ──
  // We work in pixels (TUBE_H total) so partial fills are smooth.
  const segH = TUBE_H / TUBE_CAPACITY; // px per unit
  const srcHeightPx = Math.max(0, srcFillF) * segH;

  // Build the src tube liquid using pixel heights
  // fromTube gives us the color stack; we just clip it to srcHeightPx
  const srcColor = getColorById(pourColor);

  // ── Stream path between tubes ──
  // We need to draw a stream from the tube mouth (now tilted) to the dest surface.
  // We approximate the mouth position:
  // After tilt, the mouth (top of tube = transformOrigin) is at:
  //   abs = fromPos + translate(moveX, moveY-50)  (screen coords relative to grid)
  // The bottom of the stream = dest tube surface = toPos.y + 8 + (1 - destFillF/TUBE_CAPACITY)*TUBE_H
  const isPour = phase === "pour";
  const streamColor = srcColor ? srcColor.top : "#4D96FF";

  // Stream start: opening of tilted tube ≈ top-center of flying tube element
  // Since transformOrigin is top-center of the element (fromPos.x + TUBE_W/2, fromPos.y),
  // and we translate by (moveX, moveY-50), the pivot stays at:
  //   x = fromPos.x + TUBE_W/2 + moveX  → actually pivot moves with translate
  // Let's use approximate screen positions:
  const streamStartX = fromPos.x + TUBE_W / 2 + moveX;
  const streamStartY = fromPos.y + moveY - 50 + 8; // just below the cap
  // Stream end: top surface of dest liquid
  const destLiquidTopY = toPos.y + 8 + (1 - destFillF / TUBE_CAPACITY) * TUBE_H;
  const streamEndX = toPos.x + TUBE_W / 2;
  const streamEndY = destLiquidTopY;

  // SVG bounding box (relative to grid)
  const svgLeft = Math.min(streamStartX, streamEndX) - 10;
  const svgTop = Math.min(streamStartY, streamEndY) - 10;
  const svgRight = Math.max(streamStartX, streamEndX) + 10;
  const svgBottom = Math.max(streamStartY, streamEndY) + 10;
  const svgW = svgRight - svgLeft;
  const svgH = svgBottom - svgTop;
  // Local coords inside SVG
  const lx1 = streamStartX - svgLeft;
  const ly1 = streamStartY - svgTop;
  const lx2 = streamEndX - svgLeft;
  const ly2 = streamEndY - svgTop;

  // Stream thickness tapers: wide at source, narrow at dest
  const streamW = 7;
  const streamPath = `M ${lx1 - streamW / 2} ${ly1}
    C ${lx1 - streamW / 2} ${(ly1 + ly2) / 2},
      ${lx2 - 2} ${(ly1 + ly2) / 2},
      ${lx2 - 2} ${ly2}
    L ${lx2 + 2} ${ly2}
    C ${lx2 + 2} ${(ly1 + ly2) / 2},
      ${lx1 + streamW / 2} ${(ly1 + ly2) / 2},
      ${lx1 + streamW / 2} ${ly1} Z`;

  const streamProgress =
    pourCount > 0
      ? 1 - (srcFillF - (fromTube.length - pourCount)) / pourCount
      : 0;

  return (
    <>
      {/* Flying tube */}
      <div
        style={{
          position: "absolute",
          left: fromPos.x,
          top: fromPos.y,
          width: TUBE_W,
          transform: transforms[phase] || transforms.rise,
          transition: transitions[phase] || "none",
          zIndex: 60,
          transformOrigin: "50% 0%",
          pointerEvents: "none",
        }}
      >
        <div
          style={{
            width: TUBE_W,
            height: 8,
            borderRadius: "6px 6px 0 0",
            background: "rgba(255,255,255,0.25)",
          }}
        />
        <div
          style={{
            width: TUBE_W,
            height: TUBE_H,
            borderRadius: "0 0 28px 28px",
            border: "2.5px solid #FFD93D",
            background: "rgba(255,255,255,0.06)",
            backdropFilter: "blur(4px)",
            overflow: "hidden",
            display: "flex",
            flexDirection: "column",
            boxShadow: "0 0 20px #FFD93D88",
            position: "relative",
          }}
        >
          <div
            style={{
              position: "absolute",
              top: 0,
              left: 8,
              width: 8,
              height: "70%",
              background: "rgba(255,255,255,0.12)",
              borderRadius: "0 0 4px 4px",
            }}
          />
          {(() => {
            const reversed = [...fromTube].reverse();
            const runs = [];
            reversed.forEach((cid) => {
              if (runs.length && runs[runs.length - 1].cid === cid)
                runs[runs.length - 1].count++;
              else runs.push({ cid, count: 1 });
            });
            const poured = fromTube.length - srcFillF;
            const items = [];
            let consumed = 0;
            for (let ri = 0; ri < runs.length; ri++) {
              const { cid, count } = runs[ri];
              const pouredFromThisRun = Math.min(
                count,
                Math.max(0, poured - consumed),
              );
              const remaining = count - pouredFromThisRun;
              consumed += count;
              if (remaining <= 0) continue;
              const blockH = remaining * segH;
              const isBottom = ri === runs.length - 1;
              items.push({ cid, blockH, isBottom });
            }
            const emptyH = TUBE_H - srcHeightPx;
            const result = [];
            if (emptyH > 0)
              result.push(
                <div key="empty" style={{ height: emptyH, flexShrink: 0 }} />,
              );
            items.forEach(({ cid, blockH, isBottom }, i) => {
              result.push(
                <div
                  key={i}
                  style={{
                    width: "100%",
                    height: blockH,
                    flexShrink: 0,
                    background: blockBg(cid),
                    borderRadius: isBottom ? "0 0 26px 26px" : "0",
                  }}
                />,
              );
            });
            return result;
          })()}
        </div>
      </div>

      {/* Liquid stream SVGam SVG — visible only during pour */}
      {isPour && streamProgress > 0.02 && streamProgress < 0.98 && (
        <svg
          style={{
            position: "absolute",
            left: svgLeft,
            top: svgTop,
            width: svgW,
            height: svgH,
            pointerEvents: "none",
            zIndex: 58,
            overflow: "visible",
          }}
        >
          <defs>
            <linearGradient id="streamGrad" x1="0" y1="0" x2="0" y2="1">
              <stop offset="0%" stopColor={streamColor} stopOpacity="0.9" />
              <stop offset="100%" stopColor={streamColor} stopOpacity="0.5" />
            </linearGradient>
          </defs>
          <path
            d={streamPath}
            fill="url(#streamGrad)"
            style={{ filter: `drop-shadow(0 0 3px ${streamColor}88)` }}
          />
          {/* Droplets falling down the stream */}
          {[0.25, 0.5, 0.75].map((t, i) => {
            const dropX = lx1 + (lx2 - lx1) * t;
            const dropY = ly1 + (ly2 - ly1) * t * t; // accelerate
            return (
              <circle
                key={i}
                cx={dropX}
                cy={dropY}
                r={3}
                fill={streamColor}
                opacity={0.7}
              />
            );
          })}
        </svg>
      )}

      {/* Dest fill overlay — receives continuous destFillF */}
      <DestOverlay
        tube={toFillAfterTube}
        fillF={destFillF}
        left={toPos.x}
        top={toPos.y}
      />
    </>
  );
}

// Pure display component — fillF is a continuous float
function DestOverlay({ tube, fillF, left, top }) {
  const segH = TUBE_H / TUBE_CAPACITY;
  const fillPx = Math.min(fillF, TUBE_CAPACITY) * segH;
  const emptyH = TUBE_H - fillPx;

  const reversed = [...tube].reverse();
  const runs = [];
  reversed.forEach((cid) => {
    if (runs.length && runs[runs.length - 1].cid === cid)
      runs[runs.length - 1].count++;
    else runs.push({ cid, count: 1 });
  });

  let remaining = fillPx;
  const blocks = [];
  for (let ri = 0; ri < runs.length; ri++) {
    const { cid, count } = runs[ri];
    const runMaxH = count * segH;
    const blockH = Math.min(runMaxH, remaining);
    if (blockH <= 0) break;
    remaining -= blockH;
    const isLast = ri === runs.length - 1 || remaining <= 0;
    blocks.push({ cid, blockH, isLast });
    if (remaining <= 0) break;
  }

  return (
    <div
      style={{
        position: "absolute",
        left,
        top,
        width: TUBE_W,
        pointerEvents: "none",
        zIndex: 55,
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        gap: 0,
      }}
    >
      <div style={{ width: TUBE_W, height: 8 }} />
      <div
        style={{
          width: TUBE_W,
          height: TUBE_H,
          borderRadius: "0 0 28px 28px",
          overflow: "hidden",
          display: "flex",
          flexDirection: "column",
          background: "transparent",
        }}
      >
        {emptyH > 0 && <div style={{ height: emptyH, flexShrink: 0 }} />}
        {blocks.map((b, i) => (
          <div
            key={i}
            style={{
              width: "100%",
              height: b.blockH,
              flexShrink: 0,
              background: blockBg(b.cid),
              borderRadius: b.isLast ? "0 0 26px 26px" : "0",
            }}
          />
        ))}
      </div>
    </div>
  );
}

function sleep(ms) {
  return new Promise((r) => setTimeout(r, ms));
}

// ─── LevelNavigator ──────────────────────────────────────────────────────────
// ---------- HUD widgets ----------

function LevelNavigator({ levelIdx, setLevelIdx }) {
  const [inputVal, setInputVal] = useState(String(levelIdx + 1));
  const [editing, setEditing] = useState(false);

  // Keep input in sync when navigating with buttons
  useEffect(() => {
    if (!editing) setInputVal(String(levelIdx + 1));
  }, [levelIdx, editing]);

  const go = (n) => {
    const clamped = Math.max(0, Math.min(MAX_LEVEL - 1, n));
    setLevelIdx(clamped);
    setInputVal(String(clamped + 1));
    setEditing(false);
  };

  const handleKey = (e) => {
    if (e.key === "Enter") {
      const n = parseInt(inputVal, 10);
      if (!isNaN(n)) go(n - 1);
    }
  };

  const cfg = getLevelConfig(levelIdx);
  const diffLabel =
    cfg.colors <= 3
      ? "Facile"
      : cfg.colors <= 5
        ? "Moyen"
        : cfg.colors <= 7
          ? "Difficile"
          : "Expert";
  const diffColor =
    cfg.colors <= 3
      ? "#6BCB77"
      : cfg.colors <= 5
        ? "#FFD93D"
        : cfg.colors <= 7
          ? "#FF922B"
          : "#FF6B6B";

  return (
    <div
      style={{
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        gap: 8,
        marginTop: 16,
      }}
    >
      <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
        <button
          onClick={() => go(levelIdx - 1)}
          disabled={levelIdx === 0}
          style={{
            width: 36,
            height: 36,
            borderRadius: "50%",
            border: "none",
            background:
              levelIdx === 0
                ? "rgba(255,255,255,0.05)"
                : "rgba(255,255,255,0.12)",
            color: levelIdx === 0 ? "rgba(255,255,255,0.2)" : "#fff",
            fontSize: 18,
            cursor: levelIdx === 0 ? "not-allowed" : "pointer",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
          }}
        >
          ‹
        </button>

        <div
          style={{
            display: "flex",
            alignItems: "center",
            gap: 6,
            background: "rgba(255,255,255,0.07)",
            borderRadius: 12,
            padding: "6px 14px",
            border: "1px solid rgba(255,255,255,0.12)",
          }}
        >
          <span style={{ color: "rgba(255,255,255,0.5)", fontSize: 12 }}>
            Niveau
          </span>
          <input
            value={inputVal}
            onChange={(e) => {
              setEditing(true);
              setInputVal(e.target.value);
            }}
            onBlur={() => {
              const n = parseInt(inputVal, 10);
              if (!isNaN(n)) go(n - 1);
              else {
                setInputVal(String(levelIdx + 1));
                setEditing(false);
              }
            }}
            onKeyDown={handleKey}
            style={{
              width: 52,
              textAlign: "center",
              background: "transparent",
              border: "none",
              color: "#fff",
              fontSize: 16,
              fontWeight: 700,
              outline: "none",
            }}
          />
          <span style={{ color: "rgba(255,255,255,0.3)", fontSize: 12 }}>
            / {MAX_LEVEL.toLocaleString()}
          </span>
        </div>

        <button
          onClick={() => go(levelIdx + 1)}
          disabled={levelIdx >= MAX_LEVEL - 1}
          style={{
            width: 36,
            height: 36,
            borderRadius: "50%",
            border: "none",
            background:
              levelIdx >= MAX_LEVEL - 1
                ? "rgba(255,255,255,0.05)"
                : "rgba(255,255,255,0.12)",
            color: levelIdx >= MAX_LEVEL - 1 ? "rgba(255,255,255,0.2)" : "#fff",
            fontSize: 18,
            cursor: levelIdx >= MAX_LEVEL - 1 ? "not-allowed" : "pointer",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
          }}
        >
          ›
        </button>
      </div>

      <div
        style={{
          fontSize: 11,
          fontWeight: 700,
          color: diffColor,
          letterSpacing: 1,
          textTransform: "uppercase",
          textShadow: `0 0 8px ${diffColor}88`,
        }}
      >
        {diffLabel} · {cfg.colors} couleurs
      </div>
    </div>
  );
}

// ─── Stars ────────────────────────────────────────────────────────────────────
function Stars({ count }) {
  return (
    <div style={{ display: "flex", gap: 6, justifyContent: "center" }}>
      {[1, 2, 3].map((i) => (
        <span
          key={i}
          style={{
            fontSize: 28,
            color: i <= count ? "#FFD93D" : "rgba(255,255,255,0.2)",
            filter: i <= count ? "drop-shadow(0 0 6px #FFD93D)" : "none",
            transition: "all 0.4s",
          }}
        >
          ★
        </span>
      ))}
    </div>
  );
}

