// ─── CoinMultiplier ───────────────────────────────────────────────────────────
// Zones: [1.5, 2, 3, 2, 1.5] over 5 equal segments
const MULT_ZONES = [1.5, 2, 3, 2, 1.5];
const MULT_COLORS = ["#4D96FF", "#6BCB77", "#FFD700", "#6BCB77", "#4D96FF"];
const MULT_LABELS = ["×1.5", "×2", "×3", "×2", "×1.5"];

// ---------- Reward / coin multiplier modal ----------

function CoinMultiplier({ coinsEarned, adsDisabled, onCollect, onDecline }) {
  const [pos, setPos] = useState(0); // 0..1 cursor position
  const [dir, setDir] = useState(1); // 1 or -1
  const [stopped, setStopped] = useState(false);
  const [adPlaying, setAdPlaying] = useState(false);
  const [adCount, setAdCount] = useState(5);
  const [showDecline, setShowDecline] = useState(false);
  const [collected, setCollected] = useState(false);
  const rafRef = useRef(null);
  const lastRef = useRef(null);
  const posRef = useRef(0);
  const dirRef = useRef(1);

  // Auto-move cursor
  useEffect(() => {
    if (stopped) return;
    // Speed varies by zone: slower on ×1.5, a bit faster on ×2, fast on ×3
    // zones: [1.5, 2, 3, 2, 1.5] → each zone is 0.2 wide
    const ZONE_SPEEDS = [0.0008, 0.0012, 0.0022, 0.0012, 0.0008];
    const tick = (ts) => {
      if (!lastRef.current) lastRef.current = ts;
      const dt = ts - lastRef.current;
      lastRef.current = ts;
      const zone = Math.min(4, Math.floor(posRef.current * 5));
      const speed = ZONE_SPEEDS[zone];
      posRef.current += dirRef.current * speed * dt;
      if (posRef.current >= 1) {
        posRef.current = 1;
        dirRef.current = -1;
      }
      if (posRef.current <= 0) {
        posRef.current = 0;
        dirRef.current = 1;
      }
      setPos(posRef.current);
      setDir(dirRef.current);
      rafRef.current = requestAnimationFrame(tick);
    };
    rafRef.current = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(rafRef.current);
  }, [stopped]);

  // Show decline button after 2s
  useEffect(() => {
    const t = setTimeout(() => setShowDecline(true), 2000);
    return () => clearTimeout(t);
  }, []);

  const zoneIdx = Math.min(4, Math.floor(posRef.current * 5));
  const multiplier = MULT_ZONES[zoneIdx];
  const zoneColor = MULT_COLORS[zoneIdx];
  const finalCoins = Math.round(coinsEarned * multiplier);

  const handleStop = () => {
    if (stopped || adPlaying) return;
    setStopped(true);
    if (adsDisabled) {
      setCollected(true);
      setTimeout(() => onCollect(finalCoins), 400);
      return;
    }
    setAdPlaying(true);
    setAdCount(5);
    let c = 5;
    const t = setInterval(() => {
      c--;
      setAdCount(c);
      if (c <= 0) {
        clearInterval(t);
        setAdPlaying(false);
        setCollected(true);
        setTimeout(() => onCollect(finalCoins), 600);
      }
    }, 1000);
  };

  // Track width for cursor positioning
  const trackW = 280;
  const cursorX = posRef.current * trackW;

  if (collected)
    return (
      <div style={{ textAlign: "center", padding: "12px 0" }}>
        <div
          style={{
            fontSize: 36,
            fontWeight: 900,
            color: "#FFD700",
            animation: "corkPop 0.4s cubic-bezier(0.34,1.56,0.64,1) both",
          }}
        >
          🪙 +{finalCoins}
        </div>
        <div
          style={{ color: "rgba(255,255,255,0.5)", fontSize: 13, marginTop: 4 }}
        >
          ×{multiplier} appliqué !
        </div>
      </div>
    );

  if (adPlaying)
    return (
      <div style={{ textAlign: "center", padding: "12px 0" }}>
        <div
          style={{
            fontSize: 13,
            color: "rgba(255,255,255,0.45)",
            marginBottom: 8,
          }}
        >
          Publicité en cours…
        </div>
        <div
          style={{
            width: 200,
            height: 6,
            background: "rgba(255,255,255,0.1)",
            borderRadius: 3,
            margin: "0 auto 12px",
            overflow: "hidden",
          }}
        >
          <div
            style={{
              height: "100%",
              borderRadius: 3,
              background: zoneColor,
              width: `${((5 - adCount) / 5) * 100}%`,
              transition: "width 0.9s linear",
            }}
          />
        </div>
        <div
          style={{
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            gap: 8,
            background: "rgba(255,210,0,0.12)",
            borderRadius: 14,
            padding: "8px 20px",
            border: `1px solid ${zoneColor}44`,
          }}
        >
          <span style={{ fontSize: 20 }}>🪙</span>
          <span style={{ color: "#FFD700", fontWeight: 900, fontSize: 20 }}>
            +{finalCoins}
          </span>
          <span style={{ color: "rgba(255,255,255,0.5)", fontSize: 12 }}>
            ×{multiplier} en attente
          </span>
        </div>
        <div
          style={{ color: "rgba(255,255,255,0.3)", fontSize: 12, marginTop: 8 }}
        >
          Fermeture dans {adCount}s…
        </div>
      </div>
    );

  return (
    <div style={{ textAlign: "center" }}>
      <div
        style={{
          color: "rgba(255,255,255,0.7)",
          fontSize: 13,
          marginBottom: 10,
          fontWeight: 600,
        }}
      >
        Arrêtez le curseur pour multiplier vos pièces !
      </div>

      {/* Scale + cursor */}
      <div
        style={{
          position: "relative",
          width: trackW,
          margin: "0 auto",
          userSelect: "none",
        }}
      >
        {/* Zone segments */}
        <div
          style={{
            display: "flex",
            height: 44,
            borderRadius: 10,
            overflow: "hidden",
            boxShadow: "0 2px 12px rgba(0,0,0,0.4)",
            marginBottom: 0,
          }}
        >
          {MULT_ZONES.map((m, i) => (
            <div
              key={i}
              style={{
                flex: 1,
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                background: MULT_COLORS[i],
                opacity: 0.85,
                borderRight: i < 4 ? "1px solid rgba(0,0,0,0.15)" : "none",
              }}
            >
              <span
                style={{
                  color: "#fff",
                  fontWeight: 900,
                  fontSize: 14,
                  textShadow: "0 1px 3px rgba(0,0,0,0.4)",
                }}
              >
                {MULT_LABELS[i]}
              </span>
            </div>
          ))}
        </div>

        {/* Cursor */}
        <div
          style={{
            position: "absolute",
            top: -10,
            left: cursorX - 2,
            width: 4,
            height: 64,
            background: "#fff",
            borderRadius: 2,
            boxShadow: `0 0 12px ${zoneColor}, 0 0 4px #fff`,
            pointerEvents: "none",
            transition: "box-shadow 0.1s",
          }}
        />

        {/* Cursor arrow indicator */}
        <div
          style={{
            position: "absolute",
            top: -18,
            left: cursorX - 8,
            width: 0,
            height: 0,
            borderLeft: "8px solid transparent",
            borderRight: "8px solid transparent",
            borderTop: `10px solid ${zoneColor}`,
            filter: `drop-shadow(0 0 4px ${zoneColor})`,
            pointerEvents: "none",
          }}
        />
      </div>

      {/* Current multiplier badge */}
      <div
        style={{
          marginTop: 12,
          marginBottom: 14,
          display: "inline-flex",
          alignItems: "center",
          gap: 6,
          background: `${zoneColor}22`,
          border: `1px solid ${zoneColor}66`,
          borderRadius: 20,
          padding: "4px 16px",
          transition: "background 0.15s, border 0.15s",
        }}
      >
        <span style={{ color: zoneColor, fontWeight: 900, fontSize: 18 }}>
          {MULT_LABELS[zoneIdx]}
        </span>
        <span style={{ color: "rgba(255,255,255,0.5)", fontSize: 13 }}>
          = 🪙 {finalCoins} pièces
        </span>
      </div>

      {/* Stop button */}
      <div>
        <button
          onClick={handleStop}
          style={{
            background: `linear-gradient(135deg, ${zoneColor}, ${zoneColor}bb)`,
            border: "none",
            color: "#fff",
            borderRadius: 16,
            padding: "12px 36px",
            fontSize: 16,
            fontWeight: 900,
            cursor: "pointer",
            display: "block",
            margin: "0 auto",
            boxShadow: `0 4px 20px ${zoneColor}66`,
            transition: "background 0.15s, box-shadow 0.15s",
          }}
        >
          ⏹ Arrêter !
        </button>
      </div>

      {/* Decline button — appears after 2s, subtle */}
      <div
        style={{
          marginTop: 18,
          opacity: showDecline ? 1 : 0,
          transition: "opacity 0.6s ease",
          pointerEvents: showDecline ? "auto" : "none",
        }}
      >
        <button
          onClick={onDecline}
          style={{
            background: "none",
            border: "none",
            color: "rgba(255,255,255,0.25)",
            fontSize: 12,
            cursor: "pointer",
            textDecoration: "underline",
            padding: "4px 8px",
          }}
        >
          Décliner et continuer sans bonus
        </button>
      </div>
    </div>
  );
}

